            aWandererF = aWandererF ^ ((RotL64(aCross, 5U) + RotL64(aOrbiterD, 3U)) + aOrbiterB);
            aWandererC = aWandererC + (((RotL64(aIngress, 56U) + aOrbiterF) + RotL64(aOrbiterC, 35U)) + RotL64(aCarry, 29U));
