            aIngress = aIngress + (aOrbiterE ^ RotL64(aOrbiterJ, 24U));
            aIngress = aIngress + (aOrbiterG ^ RotL64(aOrbiterA, 47U));
            aIngress = aIngress + (aOrbiterC ^ RotL64(aOrbiterI, 37U));
            aIngress = aIngress + RotL64(aOrbiterK, 19U);
            aIngress = TwistMix64::DiffuseB((aIngress + aScatter));
            //
            aWandererB = aWandererB ^ ((RotL64(aIngress, 52U) + aOrbiterE) + RotL64(aOrbiterC, 12U));
            aWandererG = aWandererG + ((((RotL64(aPrevious, 39U) + aOrbiterG) + RotL64(aOrbiterD, 47U)) + RotL64(aCarry, 19U)) + aPhaseDWandererUpdateSaltB[(((31U - aIndex) + 27U)) & S_SALT1]);
            aWandererK = aWandererK ^ ((RotL64(aCross, 23U) + RotL64(aOrbiterJ, 27U)) + aOrbiterA);
            aWandererH = aWandererH + (((RotL64(aScatter, 35U) + aOrbiterK) + RotL64(aOrbiterE, 57U)) + RotL64(aCarry, 53U));
            aWandererE = aWandererE ^ ((RotL64(aPrevious, 11U) + RotL64(aOrbiterJ, 20U)) + aOrbiterF);
            aWandererF = aWandererF + ((RotL64(aCross, 43U) + RotL64(aOrbiterF, 53U)) + aOrbiterE);
            aWandererI = aWandererI ^ ((RotL64(aScatter, 27U) + RotL64(aOrbiterI, 35U)) + aOrbiterC);
            aWandererA = aWandererA + ((RotL64(aIngress, 57U) + aOrbiterK) + RotL64(aOrbiterG, 43U));
            aWandererJ = aWandererJ ^ (((RotL64(aPrevious, 48U) + RotL64(aOrbiterC, 3U)) + aOrbiterF) + aPhaseDWandererUpdateSaltD[((aIndex + 23U)) & S_SALT1]);
            //
            aCarry = aCarry + (aWandererG ^ RotL64(aWandererE, 6U));
