            //
            aScatter = (RotL64(aCross, 53U) ^ RotL64(aPrevious, 39U)) ^ (RotL64(aCarry, 21U) + RotL64(aIngress, 6U));
            aScatter = TwistMix64::DiffuseA(aScatter);
            //
            aOrbiterK = (aWandererG + RotL64(aScatter, 46U)) + 0xE5031C643D324469ULL;
            aOrbiterH = (aWandererI + RotL64(aPrevious, 57U)) + 0x359E3B8CA589B049ULL;
            aOrbiterA = (aWandererC + RotL64(aCross, 41U)) + 0x0D8A342E5BADDA51ULL;
            aOrbiterD = (aWandererK + RotL64(aIngress, 19U)) + 0x0F76FD18DDADFAE4ULL;
            aOrbiterF = ((aWandererJ + RotL64(aPrevious, 35U)) + RotL64(aCarry, 21U)) + 0xA0D0B80D288589A9ULL;
            aOrbiterJ = ((aWandererF + RotL64(aScatter, 27U)) + 0x544AF51381B32F02ULL) + aPhaseCOrbiterAssignSaltF[((aIndex + 16U)) & S_SALT1];
            aOrbiterB = ((aWandererA + RotL64(aIngress, 14U)) + RotL64(aCarry, 35U)) + 0x8575273B8328172CULL;
            aOrbiterI = ((aWandererH + RotL64(aCross, 51U)) + RotL64(aCarry, 5U)) + 0x08E9072615A9CB6CULL;
            aOrbiterC = ((aWandererB + RotL64(aPrevious, 5U)) + 0x76F12EFE348DB2E2ULL) + aPhaseCOrbiterAssignSaltC[((aIndex + 27U)) & S_SALT1];
            //
            aOrbiterK = (aOrbiterK + aOrbiterH) + 0x458846D010E608EAULL;
            aOrbiterA = ((aOrbiterA ^ aOrbiterK) ^ 0x334AD3ECA5AE640BULL) ^ aPhaseCOrbiterUpdateSaltD[(((31U - aIndex) + 9U)) & S_SALT1];
            aOrbiterA = RotL64((aOrbiterA * 0x1061543945B16DBBULL), 39U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterF) + 0x82B82BC750FAF9EFULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterD) ^ 0xAFD5734B508C7AEDULL;
            aOrbiterK = RotL64((aOrbiterK * 0x10F3F8E83F902FA1ULL), 47U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterA) + 0xBDA81685A5A0CC7EULL) + aPhaseCOrbiterUpdateSaltB[(((31U - aIndex) + 13U)) & S_SALT1];
            aOrbiterD = (aOrbiterD ^ aOrbiterJ) ^ 0xCE0CFA1D4F7643CCULL;
            aOrbiterD = RotL64((aOrbiterD * 0xC2D2666F73ECA0E7ULL), 19U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterB) + 0xE3F1EB7F42F1690FULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterH) ^ 0x824D054F6C6BBE58ULL;
            aOrbiterI = RotL64((aOrbiterI * 0x036C8E6816864705ULL), 27U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterI) + 0x1397B1EF867D1D89ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterA) ^ 0x55508F9D3F506EF8ULL;
            aOrbiterF = RotL64((aOrbiterF * 0xD5C444D5C0605273ULL), 3U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterC) + 0x7290C83E328F4AE8ULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterF) ^ 0xA57A5D161646D181ULL;
            aOrbiterH = RotL64((aOrbiterH * 0x7B620973CD90735BULL), 53U);
            //
            aOrbiterI = ((aOrbiterI + aOrbiterJ) + 0xA63E2243599A54ADULL) + aPhaseCOrbiterUpdateSaltC[(((31U - aIndex) + 25U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterI) ^ 0xD18406A16C6795D4ULL;
            aOrbiterC = RotL64((aOrbiterC * 0xE0BC6A9A1DA486D9ULL), 43U);
            //
            aOrbiterC = ((aOrbiterC + aOrbiterD) + 0x908ACB6904A5497CULL) + aPhaseCOrbiterUpdateSaltF[(((31U - aIndex) + 5U)) & S_SALT1];
            aOrbiterB = (aOrbiterB ^ aOrbiterC) ^ 0xB2051F102F224169ULL;
            aOrbiterB = RotL64((aOrbiterB * 0xE763E64C63C71517ULL), 57U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterK) + 0x16D8BD60C2FC8F0BULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterB) ^ 0xF9267239D39089A3ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0x7E5F43501C611A13ULL), 13U);
            //
            aIngress = aOrbiterF ^ RotL64(aOrbiterH, 58U);
            aIngress = aIngress + (aOrbiterA ^ RotL64(aOrbiterB, 23U));
            aIngress = aIngress + (aOrbiterK ^ RotL64(aOrbiterC, 39U));
            aIngress = aIngress + (aOrbiterD ^ RotL64(aOrbiterJ, 43U));
            aIngress = aIngress + RotL64(aOrbiterI, 19U);
            aIngress = TwistMix64::DiffuseB((aIngress + aScatter));
            //
            aWandererG = aWandererG ^ ((RotL64(aIngress, 28U) + aOrbiterH) + RotL64(aOrbiterB, 35U));
            aWandererJ = aWandererJ + ((RotL64(aPrevious, 43U) + RotL64(aOrbiterB, 47U)) + aOrbiterC);
            aWandererH = aWandererH ^ ((RotL64(aCross, 51U) + aOrbiterJ) + RotL64(aOrbiterK, 22U));
            aWandererC = aWandererC + (((RotL64(aScatter, 39U) + RotL64(aOrbiterI, 27U)) + aOrbiterJ) + RotL64(aCarry, 27U));
            aWandererF = aWandererF ^ ((RotL64(aCross, 5U) + aOrbiterF) + RotL64(aOrbiterC, 5U));
            aWandererI = aWandererI + (((RotL64(aIngress, 47U) + aOrbiterC) + RotL64(aOrbiterH, 11U)) + RotL64(aCarry, 37U));
            aWandererA = aWandererA ^ (((RotL64(aPrevious, 11U) + RotL64(aOrbiterK, 57U)) + aOrbiterD) + aPhaseCWandererUpdateSaltA[((aIndex + 15U)) & S_SALT1]);
